import "./../App.css";
import "./../index.css";

import { useState, useEffect } from "react";
import { motion, AnimatePresence, type Variants } from "motion/react";

import { Button } from "@/components/ui/button";
import { CardTitle, CardDescription } from "@/components/ui/card";
import { Avatar, AvatarImage, AvatarFallback } from "@/components/ui/avatar";
import { LoadingSpinner } from "@/components/spinner";
import { toast } from "sonner";

const bgAlt = "/bg_alt.jpeg";
const nightlogo = "/nightlogo.png";

const formContainerVariants = {
  hidden: {
    transition: {
      staggerChildren: 0.08,
      staggerDirection: -1,
      delayChildren: 0.1,
    },
  },
  visible: {
    transition: {
      delayChildren: 0.1,
      staggerChildren: 0.08,
    },
  },
};
const sceneVariants = {
  hidden: {
    transition: {
      when: "afterChildren",
      staggerChildren: 0.08,
      staggerDirection: -1,
    },
  },
  visible: {
    transition: {
      delayChildren: 0.5,
      staggerChildren: 0.08,
    },
  },
};
const itemVariants: Variants = {
  hidden: {
    y: 20,
    opacity: 0,
    transition: { ease: [0.4, 0, 0.2, 1], duration: 0.3 },
  },
  visible: {
    y: 0,
    opacity: 1,
    transition: {
      ease: [0.4, 0, 0.2, 1],
      duration: 0.5,
      type: "spring",
      stiffness: 260,
      damping: 20,
    },
  },
};

type Props = {
  service?: string;
  
  onCancel?: () => void;
  API_URL?: string;
    onContinue?: () => void;
  visible?: boolean;

};

function OAuth({
  service,
  
  onCancel,
  visible,
  onContinue,
 
}: Props) {
  const [loading, setLoading] = useState(false);
  const [shouldAnimate, setShouldAnimate] = useState(false);

  useEffect(() => {
    
    const timer = setTimeout(() => setShouldAnimate(true), 180);
    return () => clearTimeout(timer);
  }, []);
  useEffect(() => {
    if (visible === false) {
        setShouldAnimate(false);
    }
  }, [visible]);

  const permissions = [
    "email",
    "username",
    "avatar",
    "night+ status",
    "night+ sub code",
  ];

  const handleContinue = async () => {
    setLoading(true);
    try {
     
      if (localStorage.getItem("access_token")) {
        
        toast.success("Connected successfully!");
        setLoading(false);
        onContinue && onContinue(); //check if exists before calling
        
            
        return;
      }

      
      toast.error("Unexpected response.");
    } catch (err: any) {
      toast.error("Network error: " + (err?.message ?? err));
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
   if (onCancel) {
        onCancel(); //same here, check if exists before calling
        }
  };

  return (
    <div className="font flex flex-col items-center justify-center min-h-screen text-foreground">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={shouldAnimate ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.95 }}
        variants={sceneVariants}
        transition={{ duration: 0.4, ease: [0.4, 0, 0.2, 1] }}
        className="relative z-0 h-[calc(67vh+64px)] p-[24px] w-[60vw] rounded-[54px] flex flex-row bg-card border-x-[1.5px] border-t border-b border-border overflow-hidden"
      >
        <motion.div
          initial={{
            scale: 1,
            rotateY: 0,
            perspective: 800,
            transformStyle: "preserve-3d",
            filter: "blur(25px) brightness(1)",
            x: 15,
          }}
          animate={
            shouldAnimate
              ? {
                  scale: 1.02,
                  rotateY: 8,
                  perspective: 800,
                  transformStyle: "preserve-3d",
                  filter: "blur(0px) brightness(0.95)",
                  x: 0,
                }
              : {
                  scale: 0.9,
                  rotateY: 0,
                  perspective: 800,
                  transformStyle: "preserve-3d",
                  filter: "blur(15px) brightness(1.5)",
                  x: 15,
                }
          }
          transition={{
            duration: 0.3,
            delay: 0.1,
            ease: [0.4, 0, 0.2, 1],
            rotateY: { duration: 0.4 },
            scale: { duration: 0.4 },
            x: { duration: 0.5 },
          }}
          style={{
            transformOrigin: "right center",
          }}
          className="relative flex-1 overflow-hidden w-full rounded-[30px] h-full"
        >
          <motion.img
            src={bgAlt}
            alt="Visual background"
            initial={{ scale: 1.1, x: 15 }}
            animate={shouldAnimate ? { scale: 1.15, x: 0 } : { scale: 1.1, x: 15 }}
            transition={{
              duration: 0.4,
              delay: 0.15,
              ease: [0.4, 0, 0.2, 1],
            }}
            className="w-full rounded-[30px] h-full object-cover"
            style={{ transformOrigin: "center center" }}
          />
        </motion.div>

        <div className="flex-1 flex flex-col items-center justify-center z-10 mt-[-20px] p-0">
          <motion.div
            initial={{ opacity: 0, x: -30 }}
            animate={shouldAnimate ? { opacity: 1, x: 0 } : { opacity: 0, x: -30 }}
            transition={{
              duration: 0.4,
              delay: 0.3,
              ease: [0.4, 0, 0.2, 1],
            }}
            className="logo_parent flex flex-row items-center justify-center space-x-2 pt-[30px]"
          >
            <motion.div
              initial={{ scale: 0.3, opacity: 0 }}
              animate={shouldAnimate ? { scale: 1, opacity: 1 } : { scale: 0.3, opacity: 0 }}
              transition={{
                duration: 0.8,
                delay: 0.55,
                type: "spring",
                bounce: 0.6,
                ease: [0.4, 0, 0.2, 1],
              }}
            >
              <Avatar className="w-7 h-7">
                <AvatarImage src={nightlogo} alt="Logo" />
                <AvatarFallback>NG</AvatarFallback>
              </Avatar>
            </motion.div>

            <motion.p
              initial={{ opacity: 0, x: -30 }}
              animate={shouldAnimate ? { opacity: 1, x: 0 } : { opacity: 0, x: -30 }}
              transition={{
                duration: 0.6,
                delay: 0.3,
                ease: [0.4, 0, 0.2, 1],
              }}
              className="text-bold text-foreground"
            >
              Night Network
            </motion.p>
          </motion.div>

          <AnimatePresence mode="wait">
            <motion.div
              key="oauth-consent"
              variants={formContainerVariants}
              initial="hidden"
              animate={shouldAnimate ? "visible" : "hidden"}
              exit="hidden"
              transition={{ delay: 0.6 }}
              className="w-[70%] text-center"
            >
              <motion.div variants={itemVariants} className="translate-y-[15px] mb-4">
                <CardTitle className="text-3xl scale-[0.9]">
                  {`Continue to ${service}`}
                </CardTitle>
                <CardDescription className="text-sm mt-1">
                  {`Provide ${service} with your Night info?`}
                </CardDescription>
              </motion.div>

              <motion.div variants={itemVariants} className="mt-4 mb-2">
                <CardDescription className="text-left text-sm mb-2 font-medium">
                  The following will be shared with {service}:
                </CardDescription>

                <motion.ul variants={formContainerVariants} className="text-left list-disc ml-5 space-y-1">
                  {permissions.map((p) => (
                    <motion.li key={p} variants={itemVariants} className="text-sm text-muted-foreground">
                      {p}
                    </motion.li>
                  ))}
                </motion.ul>
              </motion.div>

              <motion.div variants={itemVariants} className="mt-6 flex gap-3">
                <Button
                  className="w-[55%] rounded-full hover:cursor-pointer p-[16px] flex justify-center items-center"
                  onClick={handleContinue}
                  disabled={loading}
                >
                  {loading ? (
                    <>
                      <LoadingSpinner size={18} />
                      <span className="ml-2">Connecting…</span>
                    </>
                  ) : (
                    "Continue"
                  )}
                </Button>

                <Button
                  className="w-[45%] rounded-full hover:cursor-pointer p-[16px]"
                  variant="outline"
                  onClick={handleCancel}
                >
                  Cancel
                </Button>
              </motion.div>

              <motion.div variants={itemVariants} className="mt-4">
                <CardDescription className="text-xs text-muted-foreground">
                  By continuing you agree to share the above Night account details with {service}.
                </CardDescription>
              </motion.div>
            </motion.div>
          </AnimatePresence>
        </div>
      </motion.div>
    </div>
  );
}

export default OAuth;
