import React from "react";

type BackdropProps = {
  isOpen: boolean;
  backdropBlur?: string; // CSS blur value, e.g. '8px' or '0.5rem'
  onClick?: () => void;
  className?: string;
};

const Backdrop: React.FC<BackdropProps> = ({
  isOpen,
  backdropBlur = "8px",
  onClick,
  className = "",
}) => {
  return (
    <div
      className={`fixed inset-0 transition-opacity duration-400 ${
        isOpen ? "opacity-100 pointer-events-auto" : "opacity-0 pointer-events-none"
      } ${className}`}
      style={{
        // transparent background so backdrop-filter can take effect without adding a tint
        backgroundColor: "transparent",
        backdropFilter: isOpen && backdropBlur ? `blur(${backdropBlur})` : "none",
        WebkitBackdropFilter: isOpen && backdropBlur ? `blur(${backdropBlur})` : "none",
        transition: "opacity 400ms ease, backdrop-filter 400ms ease",
      }}
      onClick={onClick}
      aria-hidden={!isOpen}
    />
  );
};

export default Backdrop;