
import React, { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import LoginFrame from "@/components/loginFrame";
import OAuth from "@/components/oAuth";
import { ThemeProvider } from "@/components/theme-provider";
import { HeroUIProvider } from "@heroui/react";

import { Toaster } from "@/components/ui/sonner";
import { SignInWithNight } from "@/components/signInWithNight";
import Backdrop from "@/components/backdrop";

type Theme = 'system' | 'light' | 'dark';

type NightLoginOptions = {
  service: string;
  theme?: Theme;

  backdropBlur?: string;
  zIndex?: number;
  onSuccess?: (token: unknown) => void;
  onCancel?: () => void;
  API_URL?: string;
};

class NightLogin {
  constructor(options: NightLoginOptions) {
    this.options = options;
    this.modalVisible = null;
  }

  modalVisible: boolean | null;
  options: NightLoginOptions;
  parentEl: HTMLElement | null = null;
  modalChildEl: HTMLElement | null = null;
  contentEl: HTMLElement | null = null;
  root: any | undefined = undefined;

  renderTrigger(parent: string) {

    const themeChildren: React.ReactNode = React.createElement(
      React.Fragment,
      null,
      React.createElement(SignInWithNight, null),
      React.createElement(Toaster, { richColors: true })
    );


    const themeProps = {
      defaultTheme: "dark" as const,
      storageKey: "vite-ui-theme",
      children: themeChildren,
    };

    const mountEl = document.getElementById(parent);
    if (!mountEl) {
      throw new Error(`renderTrigger: element "${parent}" not found`);
    }

    createRoot(mountEl).render(
      React.createElement(
        StrictMode,
        null,
        React.createElement(ThemeProvider, themeProps)
      )
    );
  }

  /**
   * hide(child) will render the given child modal in a "closed" state (visible: false)
   * and render the backdrop with isOpen: false so exit animations run for both,
   * then it will call close() after the animation delay.
   *
   * @param child 'login' | 'oauth' - which modal to animate out
   */
  hide(child: 'login' | 'oauth' = 'login') {

    if (!this.root || !this.parentEl) return;


    this.modalVisible = false;


    const backdropEl = React.createElement(
      "div",
      { style: { position: "fixed", inset: "0", pointerEvents: "auto" } },
      React.createElement(Backdrop, {
        isOpen: false,
        backdropBlur: this.options?.backdropBlur,
        onClick: () => {}, // Prevent additional callbacks during hide animation
      })
    );


    let modalChild;
    if (child === 'login') {
      modalChild = React.createElement(LoginFrame, {
        service: this.options.service,
        visible: false,
        onCancel: () => {}, // Prevent additional callbacks during hide animation
        API_URL: this.options.API_URL,
      });
    } else {

      modalChild = React.createElement(OAuth, {
        visible: false,
        service: this.options.service,
        onContinue: () => {}, // Prevent additional callbacks during hide animation
        onCancel: () => {}, // Prevent additional callbacks during hide animation
      });
    }


    const modalEl = React.createElement(
      "div",
      {
        style: {
          position: "fixed",
          inset: "0",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          pointerEvents: "none",
        },
      },
      React.createElement(
        "div",
        {
          style: {
            pointerEvents: "auto",
            zIndex:
              this.options && this.options.zIndex
                ? Number(this.options.zIndex) + 1
                : 1000000,
          },
        },
        modalChild
      )
    );


    const heroChildren = React.createElement(
      HeroUIProvider,
      null,
      backdropEl,
      modalEl,
      React.createElement(Toaster, { richColors: true })
    );
    const themeProps = {
      defaultTheme: "dark" as const,
      storageKey: "vite-ui-theme",
      children: heroChildren,
    };

    try {

      this.root.render(
        React.createElement(StrictMode, null, React.createElement(ThemeProvider, themeProps))
      );
    } catch (e) {

      this.close();
      return;
    }


    setTimeout(() => this.close(), 400);
  }

  /**
   * Handles successful OAuth flow - triggers success callback and hides modal
   */
  handleSuccess() {
    const token = localStorage.getItem("access_token");
    this.hide('oauth');
    this.options.onSuccess && this.options.onSuccess(token);
  }

  /**
   * Handles cancelled OAuth flow - triggers cancel callback and hides modal
   */
  handleCancel() {
    localStorage.removeItem("access_token");
    this.hide('oauth');
    this.options.onCancel && this.options.onCancel();
  }

  /**
   * Handles cancelled login flow - triggers cancel callback and hides modal
   */
  handleLoginCancel() {
    localStorage.removeItem("access_token");
    this.hide('login');
    this.options.onCancel && this.options.onCancel();
  }

  /**
   * Switches the modal content to OAuth while keeping the same backdrop in place.
   * If a root already exists we'll reuse it (so backdrop does not get torn down).
   */
  oauth() {

    this.modalVisible = true;


    let container = document.getElementById("night-login-overlay");
    if (!container) {
      container = document.createElement("div");
      container.id = "night-login-overlay";

      container.style.position = "fixed";
      container.style.inset = "0";
      container.style.zIndex = String((this.options && this.options.zIndex) || 999999);
      container.style.pointerEvents = "none";
      document.body.appendChild(container);
    }

    const backdropEl = React.createElement(
      "div",
      { style: { position: "fixed", inset: "0", pointerEvents: "auto" } },
      React.createElement(Backdrop, {
        isOpen: true,
        backdropBlur: this.options?.backdropBlur,
        onClick: () => this.handleCancel(),
      })
    );


    const modalEl = React.createElement(
      "div",
      {
        style: {
          position: "fixed",
          inset: "0",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          pointerEvents: "none",
        },
      },
      React.createElement(
        "div",
        {
          style: {
            pointerEvents: "auto",
            zIndex:
              this.options && this.options.zIndex
                ? Number(this.options.zIndex) + 1
                : 1000000,
          },
        },
        React.createElement(OAuth, {

          service: this.options.service,
          onContinue: () => this.handleSuccess(),
          onCancel: () => this.handleCancel(),
        })
      )
    );

    const heroChildren = React.createElement(HeroUIProvider, null, backdropEl, modalEl, React.createElement(Toaster, { richColors: true }));
    const themeProps = { defaultTheme: "dark" as const, storageKey: "vite-ui-theme", children: heroChildren };
    const overlayChildren = React.createElement(ThemeProvider, themeProps);

    this.parentEl = container;


    if (!this.root) {
      this.root = createRoot(container);
    }
    this.root.render(React.createElement(StrictMode, null, overlayChildren));
  }

  show(root?: string) {

    this.modalVisible = true;
    void root;

    let container = document.getElementById("night-login-overlay");
    if (!container) {
      container = document.createElement("div");
      container.id = "night-login-overlay";

      container.style.position = "fixed";
      container.style.inset = "0";
      container.style.zIndex = String((this.options && this.options.zIndex) || 999999);
      container.style.pointerEvents = "none";
      document.body.appendChild(container);
    }

    const backdropEl = React.createElement(
      "div",
      { style: { position: "fixed", inset: "0", pointerEvents: "auto" } },
      React.createElement(Backdrop, {
        isOpen: true,
        backdropBlur: this.options?.backdropBlur,
        onClick: () => this.handleLoginCancel(),
      })
    );

    const modalEl = React.createElement(
      "div",
      {
        style: {
          position: "fixed",
          inset: "0",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          pointerEvents: "none",
        },
      },
      React.createElement(
        "div",
        {
          style: {
            pointerEvents: "auto",
            zIndex:
              this.options && this.options.zIndex
                ? Number(this.options.zIndex) + 1
                : 1000000,
          },
        },

        React.createElement(LoginFrame, {
          service: this.options.service,
          visible: this.modalVisible,
          onCancel: () => this.handleLoginCancel(),
          onLogin: () => this.oauth(),
          API_URL: this.options.API_URL,
        })
      )
    );

    const heroChildren = React.createElement(HeroUIProvider, null, backdropEl, modalEl, React.createElement(Toaster, { richColors: true }));
    const themeProps = { defaultTheme: "dark" as const, storageKey: "vite-ui-theme", children: heroChildren };
    const overlayChildren = React.createElement(ThemeProvider, themeProps);

    this.parentEl = container;
    this.root = createRoot(container);
    this.root.render(React.createElement(StrictMode, null, overlayChildren));
  }

  close() {
    if (this.root && this.parentEl) {
      try {
        this.root.unmount();
      } catch (e) {

      }

      if (this.parentEl.parentNode) {
        this.parentEl.parentNode.removeChild(this.parentEl);
      }

      this.root = undefined;
      this.parentEl = null;
    }
  }
}


; (window as any).NightLogin = (window as any).NightLogin || NightLogin;

export default NightLogin;
